import React, { useState, useEffect, useRef, useCallback } from 'react';
import { View, StyleSheet, Pressable, Animated, Dimensions, StatusBar, Alert, Platform } from 'react-native';
import { SafeImage } from '@/components/SafeImage';
import { ThemedText } from '@/components/ThemedText';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import { useTheme } from '@/hooks/useTheme';
import { Ionicons, MaterialCommunityIcons } from '@expo/vector-icons';
import { useNavigation, useRoute } from '@react-navigation/native';
import { LinearGradient } from 'expo-linear-gradient';
import * as Haptics from 'expo-haptics';
import { Audio } from 'expo-av';
import { useAuth } from '@/hooks/useAuth';
import { useApi } from '@/hooks/useApi';
import socketService from '@/services/socket';
import WebView from 'react-native-webview';

const { width: SCREEN_WIDTH } = Dimensions.get('window');

// ... (CallData interface remains same)

export default function VoiceCallScreen() {
  const insets = useSafeAreaInsets();
  const navigation = useNavigation<any>();
  const route = useRoute<any>();
  const { userId, userName, userPhoto, isIncoming, callData: incomingCallData, callerId, callAccepted } = route.params || {};
  const { token: authToken, user } = useAuth();
  const { post, get } = useApi();

  const [callStatus, setCallStatus] = useState<any>('initializing');
  const [callDuration, setCallDuration] = useState(0);
  const [isMuted, setIsMuted] = useState(false);
  const [isSpeakerOn, setIsSpeakerOn] = useState(false);
  const [callData, setCallData] = useState<any>(incomingCallData || null);

  // ANIMATIONS
  const pulseAnim = useRef(new Animated.Value(1)).current;
  const fadeAnim = useRef(new Animated.Value(0)).current;
  const waveAnim1 = useRef(new Animated.Value(0)).current;

  // REFS
  const soundRef = useRef<Audio.Sound | null>(null);
  const durationInterval = useRef<NodeJS.Timeout | null>(null);
  const webViewRef = useRef<WebView | null>(null);

  /**
   * IMPROVED RINGTONE IMPLEMENTATION
   */
  const manageAudio = useCallback(async (action: 'play_ringtone' | 'stop') => {
    try {
      if (action === 'stop') {
        if (soundRef.current) {
          await soundRef.current.stopAsync();
          await soundRef.current.unloadAsync();
          soundRef.current = null;
        }
        return;
      }

      // Prepare Audio Session
      await Audio.setAudioModeAsync({
        allowsRecordingIOS: true, // Needed for mic later
        playsInSilentModeIOS: true,
        staysActiveInBackground: true,
        shouldRouteThroughEarpieceAndroid: false,
      });

      // Avoid double playing
      if (soundRef.current) return;

      const { sound } = await Audio.Sound.createAsync(
        // High-quality modern ringback tone
        { uri: 'https://www.soundjay.com/phone/phone-calling-1.mp3' },
        { shouldPlay: true, isLooping: true, volume: 1.0 }
      );
      soundRef.current = sound;
    } catch (err) {
      console.log('Audio Error:', err);
    }
  }, []);

  // Sync Audio with Call Status
  useEffect(() => {
    if (callStatus === 'ringing' || callStatus === 'connecting') {
      manageAudio('play_ringtone');
    } else {
      manageAudio('stop');
    }
  }, [callStatus, manageAudio]);

  // Initial UI Animation
  useEffect(() => {
    Animated.timing(fadeAnim, { toValue: 1, duration: 800, useNativeDriver: true }).start();

    // Looping Pulse for Avatar
    Animated.loop(
      Animated.sequence([
        Animated.timing(pulseAnim, { toValue: 1.1, duration: 1500, useNativeDriver: true }),
        Animated.timing(pulseAnim, { toValue: 1, duration: 1500, useNativeDriver: true }),
      ])
    ).start();
  }, []);

  // Handle End Call logic
  const handleEndCall = useCallback(() => {
    manageAudio('stop');
    setCallStatus('ended');
    // ... rest of your socket logic ...
    setTimeout(() => navigation.goBack(), 1000);
  }, [navigation, manageAudio]);

  const getStatusText = () => {
    if (callStatus === 'connected') return formatDuration(callDuration);
    if (callStatus === 'ringing') return isIncoming ? 'Incoming...' : 'Calling...';
    return callStatus.charAt(0).toUpperCase() + callStatus.slice(1);
  };

  const formatDuration = (s: number) => `${Math.floor(s/60).toString().padStart(2, '0')}:${(s%60).toString().padStart(2, '0')}`;

  return (
    <View style={styles.container}>
      <StatusBar barStyle="light-content" />
      <LinearGradient colors={['#1a1a2e', '#16213e', '#0f3460']} style={StyleSheet.absoluteFill} />

      {/* TOP HEADER */}
      <View style={[styles.header, { paddingTop: insets.top + 10 }]}>
        <View style={styles.encryptionBadge}>
          <Ionicons name="lock-closed" size={12} color="#4ade80" />
          <ThemedText style={styles.encryptionText}>End-to-End Encrypted</ThemedText>
        </View>
      </View>

      {/* CENTER CONTENT - MOVED UP */}
      <View style={styles.mainContent}>
        <Animated.View style={[styles.avatarContainer, { transform: [{ scale: pulseAnim }] }]}>
          <View style={styles.avatarGlow} />
          <SafeImage 
            source={{ uri: userPhoto || 'https://via.placeholder.com/150' }} 
            style={styles.avatar} 
          />
        </Animated.View>

        <ThemedText style={styles.userName}>{userName || 'User'}</ThemedText>

        <View style={styles.statusRow}>
          {callStatus === 'connected' && <View style={styles.liveDot} />}
          <ThemedText style={[styles.statusText, callStatus === 'connected' && styles.connectedText]}>
            {getStatusText()}
          </ThemedText>
        </View>
      </View>

      {/* BOTTOM CONTROLS */}
      <View style={[styles.controlsContainer, { paddingBottom: insets.bottom + 40 }]}>
        {isIncoming && callStatus === 'ringing' ? (
          <View style={styles.buttonRow}>
            <Pressable style={[styles.roundBtn, styles.declineBtn]} onPress={handleEndCall}>
              <Ionicons name="call" size={32} color="white" style={{ transform: [{ rotate: '135deg' }] }} />
            </Pressable>
            <Pressable style={[styles.roundBtn, styles.acceptBtn]} onPress={() => setCallStatus('connected')}>
              <Ionicons name="call" size={32} color="white" />
            </Pressable>
          </View>
        ) : (
          <>
            <View style={styles.optionsRow}>
              <View style={styles.optionCol}>
                <Pressable style={[styles.optionBtn, isMuted && styles.activeOption]} onPress={() => setIsMuted(!isMuted)}>
                  <Ionicons name={isMuted ? "mic-off" : "mic"} size={24} color="white" />
                </Pressable>
                <ThemedText style={styles.optionLabel}>Mute</ThemedText>
              </View>

              <View style={styles.optionCol}>
                <Pressable style={[styles.optionBtn, isSpeakerOn && styles.activeOption]} onPress={() => setIsSpeakerOn(!isSpeakerOn)}>
                  <Ionicons name="volume-high" size={24} color="white" />
                </Pressable>
                <ThemedText style={styles.optionLabel}>Speaker</ThemedText>
              </View>
            </View>

            <Pressable style={[styles.roundBtn, styles.endBtn]} onPress={handleEndCall}>
              <Ionicons name="call" size={32} color="white" style={{ transform: [{ rotate: '135deg' }] }} />
            </Pressable>
          </>
        )}
      </View>
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, backgroundColor: '#000' },
  header: { alignItems: 'center', width: '100%' },
  encryptionBadge: { 
    flexDirection: 'row', 
    alignItems: 'center', 
    backgroundColor: 'rgba(255,255,255,0.1)', 
    paddingHorizontal: 12, 
    paddingVertical: 4, 
    borderRadius: 20 
  },
  encryptionText: { color: '#4ade80', fontSize: 10, marginLeft: 4, fontWeight: '600' },

  // Positioning avatar higher
  mainContent: { 
    flex: 3, 
    alignItems: 'center', 
    justifyContent: 'center', // This keeps it centered within the top 3/4 of screen
    marginTop: -40 
  },
  avatarContainer: { 
    width: 160, 
    height: 160, 
    borderRadius: 80, 
    marginBottom: 20,
    justifyContent: 'center',
    alignItems: 'center'
  },
  avatar: { width: 150, height: 150, borderRadius: 75, borderWidth: 3, borderColor: 'rgba(255,255,255,0.2)' },
  avatarGlow: { 
    position: 'absolute', 
    width: 180, 
    height: 180, 
    borderRadius: 90,
    backgroundColor: 'rgba(99, 102, 241, 0.1)' 
  },
  userName: { fontSize: 32, fontWeight: 'bold', color: '#fff', marginBottom: 10 },
  statusRow: { flexDirection: 'row', alignItems: 'center' },
  statusText: { fontSize: 18, color: 'rgba(255,255,255,0.6)' },
  connectedText: { color: '#4ade80', fontWeight: 'bold', letterSpacing: 1 },
  liveDot: { width: 8, height: 8, borderRadius: 4, backgroundColor: '#4ade80', marginRight: 8 },

  controlsContainer: { flex: 1, justifyContent: 'flex-end', alignItems: 'center' },
  buttonRow: { flexDirection: 'row', gap: 60, marginBottom: 20 },
  optionsRow: { flexDirection: 'row', gap: 40, marginBottom: 40 },
  optionCol: { alignItems: 'center' },
  optionBtn: { width: 56, height: 56, borderRadius: 28, backgroundColor: 'rgba(255,255,255,0.15)', justifyContent: 'center', alignItems: 'center' },
  activeOption: { backgroundColor: 'rgba(255,255,255,0.4)' },
  optionLabel: { color: '#fff', marginTop: 8, fontSize: 12 },

  roundBtn: { width: 72, height: 72, borderRadius: 36, justifyContent: 'center', alignItems: 'center', elevation: 5 },
  acceptBtn: { backgroundColor: '#22c55e' },
  declineBtn: { backgroundColor: '#ef4444' },
  endBtn: { backgroundColor: '#ef4444' },
});
